INSERT INTO business_services (slug, title, category, short_description, icon, full_content, active, display_order) VALUES
('thanh-lap-doanh-nghiep-tron-goi','Thành Lập Doanh Nghiệp Trọn Gói','THANH_LAP','Hỗ trợ trọn gói từ việc tư vấn đặt tên, chuẩn bị hồ sơ đến khi nhận Giấy chứng nhận Đăng ký Doanh nghiệp và con dấu.','Briefcase','Dịch vụ thành lập doanh nghiệp trọn gói của MH CONSULTING cam kết mang lại sự khởi đầu thuận lợi nhất cho Quý doanh nghiệp. Chúng tôi thay mặt khách hàng xử lý toàn bộ quy trình pháp lý phức tạp với Sở Kế hoạch và Đầu tư, cơ quan thuế, giúp doanh nghiệp tiết kiệm tối đa thời gian và chi phí.',TRUE,0),
('thay-doi-giay-phep-kinh-doanh','Thay Đổi Giấy Phép Kinh Doanh','THANH_LAP','Thay đổi tên công ty, địa chỉ trụ sở, người đại diện pháp luật, tăng/giảm vốn điều lệ, thay đổi thành viên hoặc ngành nghề kinh doanh.','Edit3','Khi quy mô hoặc định hướng kinh doanh thay đổi, doanh nghiệp cần thực hiện thủ tục thay đổi thông tin trên Giấy phép kinh doanh theo đúng thời hạn luật định. MH CONSULTING cung cấp giải pháp xử lý hồ sơ nhanh, chính xác, tránh các rủi ro phạt hành chính do nộp chậm hồ sơ.',TRUE,1),
('thanh-lap-ho-kinh-doanh-ca-the','Thành Lập Hộ Kinh Doanh Cá Thể','THANH_LAP','Quy trình đơn giản, nhanh chóng giúp cá nhân, nhóm cá nhân, hoặc hộ gia đình chính thức hoạt động thương mại hợp pháp.','UserCheck','Hộ kinh doanh cá thể là mô hình lý tưởng cho các cửa hàng bán lẻ, quán ăn, quán cà phê, hoặc cơ sở sản xuất quy mô nhỏ với ưu thế thủ tục đơn giản và mức thuế khoán dễ chịu. MH CONSULTING hỗ trợ đăng ký nhanh giấy chứng nhận đăng ký hộ kinh doanh tại Ủy ban nhân dân quận/huyện quản lý.',TRUE,2),
('dich-vu-ke-toan-tron-goi','Dịch Vụ Kế Toán Trọn Gói','KE_TOAN','Xử lý toàn bộ chứng từ phát sinh, hoàn thiện sổ sách kế toán, lập báo cáo tài chính cuối năm và đại diện làm việc với cơ quan thuế.','Calculator','Dịch vụ kế toán trọn gói của MH CONSULTING là giải pháp toàn diện giúp doanh nghiệp sở hữu một phòng kế toán chuyên nghiệp với chi phí chỉ bằng 1/10 so với thuê kế toán trưởng toàn thời gian. Chúng tôi chịu trách nhiệm pháp lý trọn đời đối với số liệu kế toán đã thực hiện.',TRUE,3),
('lam-so-sach-ke-toan-va-don-dep','Dịch Vụ Làm Sổ Sách & Dọn Dẹp Kế Toán','KE_TOAN','Rà soát lỗi hệ thống kế toán cũ, hoàn thiện sổ sách tồn đọng để chuẩn bị cho kỳ quyết toán thuế đầy thử thách.','FileText','Nếu doanh nghiệp của bạn đang lo lắng về hệ thống sổ sách kế toán lộn xộn từ những năm trước do nhân sự cũ bàn giao thiếu sót, dịch vụ dọn dẹp và làm lại sổ sách kế toán của MH CONSULTING sẽ nhanh chóng giúp bạn lấy lại sự an tâm tuyệt đối trước khi cơ quan thuế tiến hành thanh tra quyết toán.',TRUE,4),
('bao-cao-thue-dinh-ky-hang-thang-quy','Báo Cáo Thuế Định Kỳ (Tháng/Quý)','THUE','Kê khai thuế GTGT, TNCN, báo cáo tình hình sử dụng hóa đơn chính xác, nộp tờ khai đúng hạn để bảo đảm tuân thủ luật thuế.','BarChart2','Báo cáo thuế định kỳ là nghĩa vụ pháp lý bắt buộc đối với mọi doanh nghiệp đang hoạt động, ngay cả khi không phát sinh doanh thu. MH CONSULTING hỗ trợ lập tờ khai thuế GTGT, thuế TNCN và tạm tính thuế TNDN chuẩn xác từng con số, đảm bảo nộp tờ khai đúng hạn 100%.',TRUE,5),
('dich-vu-bao-hiem-xa-hoi-lao-dong','Bảo Hiểm Xã Hội & Lao Động','KHAC','Đăng ký mã đơn vị, báo tăng/giảm lao động, làm hồ sơ thai sản, ốm đau, chốt sổ BHXH nhanh chóng cho nhân viên.','HeartHandshake','Khai báo lao động và bảo hiểm xã hội bắt buộc là nghĩa vụ pháp lý nhằm đảm bảo quyền lợi cho người lao động và tránh vi phạm pháp luật về sử dụng lao động. MH CONSULTING cung cấp giải pháp trọn gói, tiết kiệm thời gian kê khai phần mềm BHXH điện tử.',TRUE,6),
('tam-ngung-va-giai-the-doanh-nghiep','Tạm Ngừng & Giải Thể Doanh Nghiệp','KHAC','Thủ tục tạm ngừng kinh doanh hoặc đóng cửa giải thể doanh nghiệp đúng luật, an toàn, không để lại hậu quả nợ thuế pháp lý.','UserX','Khi hoạt động kinh doanh không như kỳ vọng, doanh nghiệp cần thực hiện thủ tục tạm ngừng hoặc đóng cửa giải thể để cắt giảm tối đa chi phí quản lý và thuế. MH CONSULTING hỗ trợ các bước chốt sổ bảo hiểm, quyết toán thuế giải thể triệt để, đúng thời hạn.',TRUE,7)
ON CONFLICT (slug) DO NOTHING;

