INSERT INTO page_sections (page_key, section_key, title, subtitle, content, display_order) VALUES
('lien-he','hero','KẾT NỐI VỚI MH CONSULTING','Liên hệ nhanh','Chúng tôi luôn lắng nghe và phản hồi mọi yêu cầu trợ giúp pháp lý, báo giá của quý doanh nghiệp trong vòng 15 phút.',0),
('lien-he','consultation','GỬI YÊU CẦU TƯ VẤN','Phản hồi trong 15 phút','Vui lòng mô tả yêu cầu để chuyên viên MH CONSULTING liên hệ hỗ trợ.',1),
('home','footer-description','MH CONSULTING',NULL,'Đồng hành cùng doanh nghiệp với dịch vụ pháp lý, kế toán và thuế chuyên nghiệp.',0)
ON CONFLICT (page_key, section_key) DO NOTHING;

-- Ordered child content is inserted only when a service has no rows, making this seed restart-safe.
INSERT INTO service_detail_points (service_id, content, display_order)
SELECT s.id, x.content, x.ord - 1 FROM business_services s CROSS JOIN LATERAL unnest(ARRAY[
'Tư vấn miễn phí lựa chọn loại hình doanh nghiệp phù hợp (Cổ phần, TNHH 1 thành viên, TNHH 2 thành viên trở lên, Doanh nghiệp tư nhân).',
'Tư vấn đặt tên công ty tránh trùng lặp, tư vấn mức vốn điều lệ tối ưu và đăng ký ngành nghề kinh doanh phù hợp.',
'Soạn thảo toàn bộ hồ sơ đăng ký doanh nghiệp theo đúng quy định pháp luật hiện hành.',
'Đại diện doanh nghiệp nộp hồ sơ và nhận kết quả tại Sở Kế hoạch và Đầu tư.',
'Khắc con dấu tròn doanh nghiệp chất lượng cao và công bố mẫu dấu lên cổng thông tin quốc gia.',
'Hỗ trợ mở tài khoản ngân hàng và các thủ tục khai thuế ban đầu.']) WITH ORDINALITY x(content,ord)
WHERE s.slug='thanh-lap-doanh-nghiep-tron-goi' AND NOT EXISTS (SELECT 1 FROM service_detail_points d WHERE d.service_id=s.id);
INSERT INTO service_benefits (service_id, content, display_order)
SELECT s.id,x.content,x.ord-1 FROM business_services s CROSS JOIN LATERAL unnest(ARRAY[
'Tiết kiệm đến 90% thời gian đi lại và chờ đợi.','Cam kết không phát sinh bất kỳ chi phí ngoài hợp đồng.',
'Đội ngũ chuyên viên luật giàu kinh nghiệm xử lý hồ sơ nhanh chóng trong vòng 3 ngày làm việc.',
'Hỗ trợ tư vấn kế toán, thuế miễn phí trong suốt năm đầu tiên hoạt động.']) WITH ORDINALITY x(content,ord)
WHERE s.slug='thanh-lap-doanh-nghiep-tron-goi' AND NOT EXISTS (SELECT 1 FROM service_benefits d WHERE d.service_id=s.id);
